const fs = require('fs');
const path = require('path');

function escribir(rutaRelativa, b64) {
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(rutaRelativa);
  if (dir && dir !== '.') fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(rutaRelativa, content, 'utf8');
  console.log('OK:', rutaRelativa);
}

// Fix 1 y 2: registro-diario
// - Bug fecha/timezone: toLocaleString + toISOString devolvia el dia
//   siguiente despues de ~21:00 hora Chile. Reemplazado por
//   Intl.DateTimeFormat('en-CA', {timeZone:'America/Santiago'}), el
//   mismo patron que ya se usa en dashboard/page.tsx.
// - Bug "guardar 2-3 veces": el upsert no revisaba errores, asi que
//   si fallaba, fallaba en silencio y el usuario volvia a intentar
//   sin saber que paso. Ahora se captura el error y se muestra un
//   mensaje, sin navegar al dashboard si algo salio mal.
escribir(path.join('app', 'registro-diario', 'page.tsx'), '');

// Fix 3: notificaciones
// - Detecta si Notification.permission === 'denied' (caso tipico tras
//   reinstalar la app desde Google Play, que pide el permiso de nuevo)
//   y muestra un aviso invitando a activarlo desde Configuracion del
//   telefono, en vez de mostrar un boton "Activar" que nunca va a
//   funcionar.
escribir(path.join('components', 'ConfiguracionNotificaciones.tsx'), '');

